final:
module top_module(
    input rstn, clk, J, K,
    output reg Q,
    output Qn
);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @ (posedge clk, negedge rstn or posedge dbg_halt)
    begin
        if (!rstn)
            Q <= 1'b0;
        else
            case (Q)
                1'b0 : Q <= J;
                1'b1 : Q <= ~K;
            endcase
    end

    assign Qn = ~Q;
endmodule
